  1→import { put } from "@vercel/blob";
  2→import { requireUser } from "../../lib/auth.js";
  3→import {
  4→  getLegacySubmissions,
  5→  getPointEvents,
  6→  getUserProfile,
  7→  insertPointEvent,
  8→  isStorageUnavailableError,
  9→  upsertUserProfile,
 10→} from "../../lib/server/storage/index.js";
 11→import {
 12→  isEnrichFieldAllowed,
 13→  listCreateMissingFields,
 14→  mergePointEventsWithLegacy,
 15→  normalizeEnrichPayload,
 16→  projectPointsFromEvents,
 17→} from "../../lib/server/pointProjection.js";
 18→import { errorResponse, jsonResponse } from "../../lib/server/http.js";
 19→import {
 20→  filterEventsForViewer,
 21→  redactEventUserIds,
 22→  resolveAdminViewAccess,
 23→  toSubmissionAuthContext,
 24→  normalizeActorId,
 25→} from "../../lib/server/submissionAccess.js";
 26→import {
 27→  DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM,
 28→  buildPhotoFraudMetadata,
 29→  buildSubmissionFraudCheck,
 30→  extractPhotoMetadata,
 31→  extractPhotoMetadataFromUrl,
 32→  haversineKm,
 33→  isPhotoMetadataEffectivelyEmpty,
 34→  parseSubmissionFraudCheck,
 35→} from "../../lib/server/submissionFraud.js";
 36→import { BONAMOUSSADI_BOUNDS, isWithinBonamoussadi, isWithinCameroon } from "../../shared/geofence.js";
 37→import { BONAMOUSSADI_CURATED_SEED_EVENTS } from "../../shared/bonamoussadiSeedEvents.js";
 38→import type {
 39→  AdminSubmissionEvent,
 40→  ClientDeviceInfo,
 41→  MapScope,
 42→  PointEvent,
 43→  PointEventType,
 44→  SubmissionCategory,
 45→  SubmissionDetails,
 46→  SubmissionFraudCheck,
 47→  SubmissionInput,
 48→  SubmissionLocation,
 49→} from "../../shared/types.js";
 50→
 51→const allowedCategories: SubmissionCategory[] = ["pharmacy", "fuel_station", "mobile_money"];
 52→const allowedEventTypes: PointEventType[] = ["CREATE_EVENT", "ENRICH_EVENT"];
 53→const IP_PHOTO_MATCH_KM = Number(process.env.IP_PHOTO_MATCH_KM ?? "50") || 50;
 54→const SUBMISSION_PHOTO_MATCH_KM = DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM;
 55→const MAX_FORENSICS_FALLBACK_LOOKUPS = Number(process.env.ADMIN_FORENSICS_FALLBACK_LIMIT ?? "25") || 25;
 56→const INLINE_PHOTO_PREFIX = "data:image/";
 57→const MAX_IMAGE_BYTES = Number(process.env.MAX_SUBMISSION_IMAGE_BYTES ?? "8388608") || 8388608;
 58→const INLINE_IMAGE_REGEX = /^data:(image\/[a-z0-9.+-]+);base64,/i;
 59→const allowedImageMime = new Set(["image/jpeg", "image/jpg", "image/png", "image/webp", "image/heic", "image/heif"]);
 60→const BASE_EVENT_XP = 5;
 61→const allowedMapScopes: ReadonlySet<MapScope> = new Set(["bonamoussadi", "cameroon", "global"]);
 62→const PUBLIC_READ_CACHE_CONTROL = "public, s-maxage=30, stale-while-revalidate=300";
 63→
 64→function parseLocation(input: unknown): SubmissionLocation | null {
 65→  if (!input || typeof input !== "object") return null;
 66→  const location = input as { latitude?: unknown; longitude?: unknown };
 67→  const latitude = typeof location.latitude === "string" ? Number(location.latitude) : (location.latitude as number);
 68→  const longitude = typeof location.longitude === "string" ? Number(location.longitude) : (location.longitude as number);
 69→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 70→  return { latitude, longitude };
 71→}
 72→
 73→function hasValue(input: unknown): boolean {
 74→  if (typeof input === "string") return Boolean(input.trim());
 75→  if (typeof input === "boolean") return true;
 76→  if (typeof input === "number") return Number.isFinite(input);
 77→  if (Array.isArray(input)) return input.length > 0;
 78→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 79→  return false;
 80→}
 81→
 82→function trimString(input: unknown, maxLen = 256): string | null {
 83→  if (typeof input !== "string") return null;
 84→  const value = input.trim();
 85→  if (!value) return null;
 86→  return value.slice(0, maxLen);
 87→}
 88→
 89→function sanitizeClientDevice(input: unknown): ClientDeviceInfo | null {
 90→  if (!input || typeof input !== "object") return null;
 91→  const raw = input as Record<string, unknown>;
 92→  const deviceId = trimString(raw.deviceId, 128);
 93→  if (!deviceId) return null;
 94→  const platform = trimString(raw.platform, 64);
 95→  const userAgent = trimString(raw.userAgent, 256);
 96→  const memory = typeof raw.deviceMemoryGb === "number" && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null;
 97→  const cpu = typeof raw.hardwareConcurrency === "number" && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null;
 98→  const isLowEnd = raw.isLowEnd === true;
 99→
100→  return {
101→    deviceId,
102→    platform: platform ?? undefined,
103→    userAgent: userAgent ?? undefined,
104→    deviceMemoryGb: memory,
105→    hardwareConcurrency: cpu,
106→    isLowEnd,
107→  };
108→}
109→
110→function normalizeCategory(input: string | undefined): SubmissionCategory | null {
111→  if (!input) return null;
112→  const raw = input.trim();
113→  if (raw === "FUEL") return "fuel_station";
114→  if (raw === "MOBILE_MONEY" || raw === "KIOSK") return "mobile_money";
115→  if (raw === "PHARMACY") return "pharmacy";
116→  if (raw === "fuel_station" || raw === "mobile_money" || raw === "pharmacy") return raw;
117→  return null;
118→}
119→
120→function normalizeEventType(input: unknown): PointEventType {
121→  if (typeof input === "string" && allowedEventTypes.includes(input as PointEventType)) {
122→    return input as PointEventType;
123→  }
124→  return "CREATE_EVENT";
125→}
126→
127→function normalizeMapScope(input: string | null): MapScope {
128→  if (!input) return "bonamoussadi";
129→  const normalized = input.trim().toLowerCase();
130→  if (!allowedMapScopes.has(normalized as MapScope)) return "bonamoussadi";
131→  return normalized as MapScope;
132→}
133→
134→function stripBase64Prefix(imageBase64: string): string {
135→  const commaIndex = imageBase64.indexOf(",");
136→  return commaIndex === -1 ? imageBase64 : imageBase64.slice(commaIndex + 1);
137→}
138→
139→function isInlinePhotoData(value: unknown): value is string {
140→  return typeof value === "string" && value.startsWith(INLINE_PHOTO_PREFIX);
141→}
142→
143→function stripInlinePhotoData(event: PointEvent): PointEvent {
144→  if (!isInlinePhotoData(event.photoUrl)) return event;
145→  const { photoUrl: _photoUrl, ...rest } = event;
146→  const details = { ...(event.details ?? {}), hasPhoto: true };
147→  return { ...rest, details };
148→}
149→
150→function mimeToExtension(mime: string): string {
151→  switch (mime) {
152→    case "image/png":
153→      return "png";
154→    case "image/webp":
155→      return "webp";
156→    case "image/heic":
157→      return "heic";
158→    case "image/heif":
159→      return "heif";
160→    default:
161→      return "jpg";
162→  }
163→}
164→
165→function parseImagePayload(imageBase64: string): { imageBuffer: Buffer; mime: string; ext: string } | null {
166→  const match = imageBase64.match(INLINE_IMAGE_REGEX);
167→  if (!match) return null;
168→
169→  const mime = match[1]?.toLowerCase() ?? "";
170→  if (!allowedImageMime.has(mime)) return null;
171→
172→  const base64 = stripBase64Prefix(imageBase64);
173→  const imageBuffer = Buffer.from(base64, "base64");
174→  if (!imageBuffer.length) return null;
175→
176→  return { imageBuffer, mime, ext: mimeToExtension(mime) };
177→}
178→
179→async function uploadSubmissionPhoto(
180→  eventId: string,
181→  imageBuffer: Buffer,
182→  mime: string,
183→  ext: string,
184→): Promise<string> {
185→  const pathname = `submissions/${eventId}-${Date.now()}.${ext}`;
186→  const token = process.env.BLOB_READ_WRITE_TOKEN;
187→  const uploaded = await put(pathname, imageBuffer, {
188→    access: "public",
189→    contentType: mime,
190→    addRandomSuffix: false,
191→    token: token || undefined,
192→  });
193→  return uploaded.url;
194→}
