196→function normalizeIp(raw: string | null): string | null {
197→  if (!raw) return null;
198→  const first = raw.split(",")[0]?.trim();
199→  if (!first) return null;
200→  const cleaned = first.replace(/^\[|\]$/g, "");
201→  if (cleaned.startsWith("::ffff:")) return cleaned.slice(7);
202→  if (/^\d+\.\d+\.\d+\.\d+:\d+$/.test(cleaned)) return cleaned.split(":")[0] ?? null;
203→  return cleaned;
204→}
205→
206→function isPrivateIp(ip: string): boolean {
207→  if (ip === "127.0.0.1" || ip === "::1") return true;
208→  if (ip.startsWith("10.")) return true;
209→  if (ip.startsWith("192.168.")) return true;
210→  if (ip.startsWith("172.")) {
211→    const second = Number(ip.split(".")[1]);
212→    if (second >= 16 && second <= 31) return true;
213→  }
214→  if (ip.startsWith("fc") || ip.startsWith("fd")) return true;
215→  if (ip.startsWith("fe80:")) return true;
216→  return false;
217→}
218→
219→interface IpApiResponse {
220→  latitude?: unknown;
221→  longitude?: unknown;
222→}
223→
224→async function fetchIpLocation(ip: string): Promise<SubmissionLocation | null> {
225→  const target = `https://ipapi.co/${ip}/json/`;
226→  const controller = new AbortController();
227→  const timeout = setTimeout(() => controller.abort(), 3000);
228→  try {
229→    const res = await fetch(target, { signal: controller.signal });
230→    if (!res.ok) return null;
231→    const data = (await res.json()) as IpApiResponse;
232→    const latitude = Number(data?.latitude);
233→    const longitude = Number(data?.longitude);
234→    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
235→    return { latitude, longitude };
236→  } catch {
237→    return null;
238→  } finally {
239→    clearTimeout(timeout);
240→  }
241→}
242→
243→async function getIpLocation(request: Request): Promise<SubmissionLocation | null> {
244→  const forwarded = request.headers.get("x-forwarded-for");
245→  const realIp = request.headers.get("x-real-ip");
246→  const vercelIp = request.headers.get("x-vercel-forwarded-for");
247→  const ip = normalizeIp(vercelIp ?? forwarded ?? realIp);
248→  if (!ip || isPrivateIp(ip)) return null;
249→  return await fetchIpLocation(ip);
250→}
251→
252→function validateCreatePayload(category: SubmissionCategory, details: SubmissionDetails): string | null {
253→  const missing = listCreateMissingFields(category, details);
254→  if (missing.length > 0) return `Missing required fields: ${missing.join(", ")}`;
255→  return null;
256→}
257→
258→function getUserDisplayName(userId: string, name: string | null, email: string | null): string {
259→  if (name && name.trim()) return name.trim();
260→  if (email) {
261→    const atIndex = email.indexOf("@");
262→    if (atIndex > 0) return email.slice(0, atIndex);
263→    return email;
264→  }
265→  return userId || "Contributor";
266→}
267→
268→function getEventFraudCheck(event: PointEvent): SubmissionFraudCheck | null {
269→  const details = event.details as Record<string, unknown> | undefined;
270→  return parseSubmissionFraudCheck(details?.fraudCheck);
271→}
272→
273→function getSecondaryPhotoUrl(event: PointEvent): string | null {
274→  const details = event.details as Record<string, unknown> | undefined;
275→  const secondPhotoUrl = details?.secondPhotoUrl;
276→  if (typeof secondPhotoUrl !== "string") return null;
277→  const normalized = secondPhotoUrl.trim();
278→  return normalized || null;
279→}
280→
281→function shouldRunFallbackFraudCheck(event: PointEvent, fraudCheck: SubmissionFraudCheck | null): boolean {
282→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
283→  const secondaryUrl = getSecondaryPhotoUrl(event);
284→  if (!fraudCheck) return Boolean(primaryUrl || secondaryUrl);
285→  if (primaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.primaryPhoto)) return true;
286→  if (secondaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.secondaryPhoto)) return true;
287→  return false;
288→}
289→
290→function mergePhotoFraudMetadata(
291→  existing: SubmissionFraudCheck["primaryPhoto"],
292→  recovered: SubmissionFraudCheck["primaryPhoto"],
293→  hasPhotoUrl: boolean,
294→): SubmissionFraudCheck["primaryPhoto"] {
295→  if (!hasPhotoUrl) return existing ?? null;
296→  if (existing && !isPhotoMetadataEffectivelyEmpty(existing)) return existing;
297→  if (recovered) return recovered;
298→  return existing ?? null;
299→}
300→
301→async function buildFallbackFraudCheck(
302→  event: PointEvent,
303→  existingFraudCheck: SubmissionFraudCheck | null,
304→): Promise<SubmissionFraudCheck | null> {
305→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
306→  const secondaryUrl = getSecondaryPhotoUrl(event);
307→  if (!primaryUrl && !secondaryUrl) return existingFraudCheck;
308→
309→  const needsPrimaryRecovery = Boolean(primaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.primaryPhoto);
310→  const needsSecondaryRecovery = Boolean(secondaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.secondaryPhoto);
311→  const primaryExtracted = needsPrimaryRecovery ? await extractPhotoMetadataFromUrl(primaryUrl) : null;
312→  const secondaryExtracted = needsSecondaryRecovery ? await extractPhotoMetadataFromUrl(secondaryUrl) : null;
313→  const recoveredPrimaryPhoto = buildPhotoFraudMetadata({
314→    extracted: primaryExtracted,
315→    submissionLocation: event.location,
316→    ipLocation: null,
317→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
318→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
319→  });
320→  const recoveredSecondaryPhoto = buildPhotoFraudMetadata({
321→    extracted: secondaryExtracted,
322→    submissionLocation: event.location,
323→    ipLocation: null,
324→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
325→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
326→  });
327→  const primaryPhoto = mergePhotoFraudMetadata(existingFraudCheck?.primaryPhoto ?? null, recoveredPrimaryPhoto, Boolean(primaryUrl));
328→  const secondaryPhoto = mergePhotoFraudMetadata(
329→    existingFraudCheck?.secondaryPhoto ?? null,
330→    recoveredSecondaryPhoto,
331→    Boolean(secondaryUrl),
332→  );
333→  if (!primaryPhoto && !secondaryPhoto) return null;
334→
335→  return buildSubmissionFraudCheck({
336→    submissionLocation: existingFraudCheck?.submissionLocation ?? event.location,
337→    effectiveLocation: existingFraudCheck?.effectiveLocation ?? event.location,
338→    ipLocation: existingFraudCheck?.ipLocation ?? null,
339→    primaryPhoto,
340→    secondaryPhoto,
341→    submissionMatchThresholdKm: existingFraudCheck?.submissionMatchThresholdKm ?? SUBMISSION_PHOTO_MATCH_KM,
342→    ipMatchThresholdKm: existingFraudCheck?.ipMatchThresholdKm ?? IP_PHOTO_MATCH_KM,
343→  });
344→}
345→
346→async function buildAdminSubmissionEvents(events: PointEvent[]): Promise<AdminSubmissionEvent[]> {
347→  const sortedEvents = [...events].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
348→  const userIds = Array.from(
349→    new Set(
350→      sortedEvents
351→        .map((event) => normalizeActorId(event.userId))
352→        .filter((value) => value.length > 0),
353→    ),
354→  );
355→
356→  const profileEntries = await Promise.all(
357→    userIds.map(async (userId) => [userId, await getUserProfile(userId)] as const),
358→  );
359→  const profileByUserId = new Map(profileEntries);
360→  const output: AdminSubmissionEvent[] = [];
361→  let fallbackLookups = 0;
362→
363→  for (const event of sortedEvents) {
364→    const normalizedUserId = normalizeActorId(event.userId);
365→    const profile = profileByUserId.get(normalizedUserId) ?? null;
366→    const emailFromProfile = typeof profile?.email === "string" ? profile.email.trim().toLowerCase() : "";
367→    const email = emailFromProfile || (normalizedUserId.includes("@") ? normalizedUserId : null);
368→    const name = getUserDisplayName(normalizedUserId, profile?.name ?? null, email);
369→    let fraudCheck = getEventFraudCheck(event);
370→    if (shouldRunFallbackFraudCheck(event, fraudCheck) && fallbackLookups < MAX_FORENSICS_FALLBACK_LOOKUPS) {
371→      fallbackLookups += 1;
372→      try {
373→        fraudCheck = await buildFallbackFraudCheck(event, fraudCheck);
374→      } catch {
375→        fraudCheck = fraudCheck ?? null;
376→      }
377→    }
378→
379→    output.push({
380→      event,
381→      user: {
382→        id: normalizedUserId || event.userId,
383→        name,
384→        email,
385→      },
386→      fraudCheck,
387→    });
388→  }
389→
390→  return output;
391→}
392→
393→async function buildCombinedEvents(): Promise<PointEvent[]> {
394→  const pointEvents = (await getPointEvents()).map(stripInlinePhotoData);
395→  const legacySubmissions = await getLegacySubmissions();
396→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
397→  const seenExternalIds = new Set(
398→    merged
399→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
400→      .filter((value) => value.length > 0),
401→  );
402→  const seenPointIds = new Set(merged.map((event) => event.pointId));
403→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
404→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
405→    if (externalId && seenExternalIds.has(externalId)) continue;
406→    if (seenPointIds.has(seedEvent.pointId)) continue;
407→    merged.push(seedEvent);
408→    if (externalId) seenExternalIds.add(externalId);
409→    seenPointIds.add(seedEvent.pointId);
410→  }
411→  return merged;
412→}
