 69→function normalizeString(input: unknown): string | null {
 70→  if (typeof input !== "string") return null;
 71→  const value = input.trim();
 72→  return value || null;
 73→}
 74→
 75→function parseDateIso(input: unknown): string | null {
 76→  if (!input) return null;
 77→  if (input instanceof Date) {
 78→    if (Number.isNaN(input.getTime())) return null;
 79→    return input.toISOString();
 80→  }
 81→  if (typeof input === "string") {
 82→    const value = input.trim();
 83→    if (!value) return null;
 84→    const exifMatch = value.match(EXIF_DATE_TIME_REGEX);
 85→    if (exifMatch) {
 86→      const year = Number(exifMatch[1]);
 87→      const month = Number(exifMatch[2]);
 88→      const day = Number(exifMatch[3]);
 89→      const hour = Number(exifMatch[4]);
 90→      const minute = Number(exifMatch[5]);
 91→      const second = Number(exifMatch[6]);
 92→      const millisRaw = exifMatch[7] ?? "0";
 93→      const millis = Number(millisRaw.slice(0, 3).padEnd(3, "0"));
 94→      const utcDate = new Date(Date.UTC(year, month - 1, day, hour, minute, second, millis));
 95→      if (!Number.isNaN(utcDate.getTime())) return utcDate.toISOString();
 96→    }
 97→    const parsed = new Date(value);
 98→    if (Number.isNaN(parsed.getTime())) return null;
 99→    return parsed.toISOString();
100→  }
101→  if (typeof input === "number") {
102→    const parsed = new Date(input);
103→    if (Number.isNaN(parsed.getTime())) return null;
104→    return parsed.toISOString();
105→  }
106→  if (typeof input === "object") {
107→    const value = input as {
108→      toDate?: () => unknown;
109→      toISOString?: () => string;
110→      value?: unknown;
111→      rawValue?: unknown;
112→      year?: unknown;
113→      month?: unknown;
114→      day?: unknown;
115→      hour?: unknown;
116→      minute?: unknown;
117→      second?: unknown;
118→      millisecond?: unknown;
119→    };
120→    if (typeof value.toDate === "function") {
121→      try {
122→        const converted = value.toDate();
123→        const parsed = parseDateIso(converted);
124→        if (parsed) return parsed;
125→      } catch {
126→        // fall through
127→      }
128→    }
129→    if (typeof value.toISOString === "function") {
130→      try {
131→        const iso = value.toISOString();
132→        const parsed = parseDateIso(iso);
133→        if (parsed) return parsed;
134→      } catch {
135→        // fall through
136→      }
137→    }
138→    const fromValue = parseDateIso(value.value ?? value.rawValue);
139→    if (fromValue) return fromValue;
140→
141→    const year = Number(value.year);
142→    const month = Number(value.month);
143→    const day = Number(value.day);
144→    if (Number.isFinite(year) && Number.isFinite(month) && Number.isFinite(day)) {
145→      const hour = Number(value.hour);
146→      const minute = Number(value.minute);
147→      const second = Number(value.second);
148→      const millisecond = Number(value.millisecond);
149→      const utcDate = new Date(
150→        Date.UTC(
151→          year,
152→          month - 1,
153→          day,
154→          Number.isFinite(hour) ? hour : 0,
155→          Number.isFinite(minute) ? minute : 0,
156→          Number.isFinite(second) ? second : 0,
157→          Number.isFinite(millisecond) ? millisecond : 0,
158→        ),
159→      );
160→      if (!Number.isNaN(utcDate.getTime())) return utcDate.toISOString();
161→    }
162→  }
163→  return null;
164→}
