166→function parseLocation(input: unknown): SubmissionLocation | null {
167→  if (!input || typeof input !== "object") return null;
168→  const location = input as { latitude?: unknown; longitude?: unknown };
169→  const latitude = typeof location.latitude === "number" ? location.latitude : Number(location.latitude);
170→  const longitude = typeof location.longitude === "number" ? location.longitude : Number(location.longitude);
171→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
172→  return { latitude, longitude };
173→}
