175→function parseOptionalNumber(input: unknown): number | null {
176→  if (typeof input === "number" && Number.isFinite(input)) return input;
177→  if (typeof input === "string") {
178→    const parsed = Number(input);
179→    if (Number.isFinite(parsed)) return parsed;
180→  }
181→  return null;
182→}
