189→function parseExifStatus(input: unknown): SubmissionExifStatus | null {
190→  if (typeof input !== "string") return null;
191→  const normalized = input.trim().toLowerCase() as SubmissionExifStatus;
192→  if (!EXIF_STATUSES.has(normalized)) return null;
193→  return normalized;
