207→function toFiniteNumber(input: unknown): number | null {
208→  if (typeof input === "number" && Number.isFinite(input)) return input;
209→  if (typeof input === "string") {
210→    const parsed = Number(input.trim());
211→    if (Number.isFinite(parsed)) return parsed;
212→    return null;
213→  }
214→  return null;
215→}
