217→function toRationalNumber(input: unknown): number | null {
218→  const direct = toFiniteNumber(input);
219→  if (direct !== null) return direct;
220→  if (!input || typeof input !== "object") return null;
221→
222→  const rational = input as {
223→    numerator?: unknown;
224→    denominator?: unknown;
225→    num?: unknown;
226→    den?: unknown;
227→    value?: unknown;
228→  };
229→  const numerator = toFiniteNumber(rational.numerator ?? rational.num);
230→  const denominator = toFiniteNumber(rational.denominator ?? rational.den);
231→  if (numerator !== null && denominator !== null && denominator !== 0) {
232→    return numerator / denominator;
233→  }
234→  if ("value" in rational) return toRationalNumber(rational.value);
235→  return null;
236→}
