238→function parseDmsCoordinate(input: unknown): number | null {
239→  const direct = toRationalNumber(input);
240→  if (direct !== null) return direct;
241→  if (!Array.isArray(input) || input.length === 0) return null;
242→  const degrees = toRationalNumber(input[0]);
243→  if (degrees === null) return null;
244→  const minutes = toRationalNumber(input[1]) ?? 0;
245→  const seconds = toRationalNumber(input[2]) ?? 0;
246→  return degrees + minutes / 60 + seconds / 3600;
247→}
