249→function applyHemisphere(value: number, ref: unknown, negativeChar: "S" | "W"): number {
250→  if (typeof ref !== "string") return value;
251→  const normalized = ref.trim().toUpperCase();
252→  if (!normalized) return value;
253→  if (normalized.startsWith(negativeChar)) return -Math.abs(value);
254→  return Math.abs(value);
255→}
