257→function toGpsLocation(latInput: unknown, lonInput: unknown): SubmissionLocation | null {
258→  const latitude = toFiniteNumber(latInput);
259→  const longitude = toFiniteNumber(lonInput);
260→  if (latitude === null || longitude === null) return null;
261→  return { latitude, longitude };
262→}
