264→function extractGps(parsed: Record<string, unknown>): SubmissionLocation | null {
265→  const direct =
266→    toGpsLocation(parsed.latitude, parsed.longitude) ??
267→    toGpsLocation(parsed.lat, parsed.lon) ??
268→    toGpsLocation(parsed.lat, parsed.lng);
269→  if (direct) return direct;
270→
271→  const gpsContainer = parsed.gps && typeof parsed.gps === "object" ? (parsed.gps as Record<string, unknown>) : null;
272→  if (gpsContainer) {
273→    const nested =
274→      toGpsLocation(gpsContainer.latitude, gpsContainer.longitude) ??
275→      toGpsLocation(gpsContainer.lat, gpsContainer.lon) ??
276→      toGpsLocation(gpsContainer.lat, gpsContainer.lng);
277→    if (nested) return nested;
278→  }
279→
280→  const rawLatitude = parseDmsCoordinate(parsed.GPSLatitude ?? gpsContainer?.GPSLatitude);
281→  const rawLongitude = parseDmsCoordinate(parsed.GPSLongitude ?? gpsContainer?.GPSLongitude);
282→  if (rawLatitude === null || rawLongitude === null) return null;
283→
284→  const latitude = applyHemisphere(rawLatitude, parsed.GPSLatitudeRef ?? gpsContainer?.GPSLatitudeRef, "S");
285→  const longitude = applyHemisphere(rawLongitude, parsed.GPSLongitudeRef ?? gpsContainer?.GPSLongitudeRef, "W");
286→  return { latitude, longitude };
287→}
