289→function detectImageFormat(imageBuffer: Buffer): "jpeg" | "png" | "webp" | "heic" | "heif" | "unknown" {
290→  if (imageBuffer.length >= 3 && imageBuffer[0] === 0xff && imageBuffer[1] === 0xd8 && imageBuffer[2] === 0xff) {
291→    return "jpeg";
292→  }
293→  if (
294→    imageBuffer.length >= 8 &&
295→    imageBuffer[0] === 0x89 &&
296→    imageBuffer[1] === 0x50 &&
297→    imageBuffer[2] === 0x4e &&
298→    imageBuffer[3] === 0x47
299→  ) {
300→    return "png";
301→  }
302→  if (imageBuffer.length >= 12) {
303→    const riff = imageBuffer.subarray(0, 4).toString("ascii");
304→    const webp = imageBuffer.subarray(8, 12).toString("ascii");
305→    if (riff === "RIFF" && webp === "WEBP") return "webp";
306→  }
307→  if (imageBuffer.length >= 12 && imageBuffer.subarray(4, 8).toString("ascii") === "ftyp") {
308→    const brand = imageBuffer.subarray(8, 12).toString("ascii").toLowerCase();
309→    if (brand.startsWith("heic") || brand.startsWith("heix") || brand.startsWith("hevc") || brand.startsWith("hevx")) {
310→      return "heic";
311→    }
312→    if (brand === "heif" || brand === "mif1" || brand === "msf1") {
313→      return "heif";
314→    }
315→  }
316→  return "unknown";
317→}
