332→function metadataContext(options: ExtractPhotoMetadataOptions): string {
333→  const parts: string[] = [];
334→  const mime = normalizeString(options.mime);
335→  const ext = normalizeString(options.ext);
336→  if (mime) parts.push(`mime=${mime}`);
337→  if (ext) parts.push(`ext=${ext}`);
338→  if (typeof options.byteLength === "number" && Number.isFinite(options.byteLength) && options.byteLength > 0) {
339→    parts.push(`bytes=${Math.round(options.byteLength)}`);
340→  }
341→  return parts.join("; ");
342→}
