389→function inferRemoteExt(photoUrl: string): string | null {
390→  try {
391→    const parsed = new URL(photoUrl);
392→    const pathname = parsed.pathname;
393→    const dotIndex = pathname.lastIndexOf(".");
394→    if (dotIndex === -1) return null;
395→    const ext = pathname.slice(dotIndex + 1).toLowerCase().trim();
396→    if (!ext || ext.length > 12) return null;
397→    return ext;
398→  } catch {
399→    return null;
400→  }
