422→export function haversineKm(a: SubmissionLocation, b: SubmissionLocation): number {
423→  const toRad = (deg: number) => (deg * Math.PI) / 180;
424→  const dLat = toRad(b.latitude - a.latitude);
425→  const dLon = toRad(b.longitude - a.longitude);
426→  const lat1 = toRad(a.latitude);
427→  const lat2 = toRad(b.latitude);
428→  const sinLat = Math.sin(dLat / 2);
429→  const sinLon = Math.sin(dLon / 2);
430→  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLon * sinLon;
431→  return 2 * EARTH_RADIUS_KM * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h));
432→}
