436→  options: ExtractPhotoMetadataOptions = {},
437→): Promise<ExtractedPhotoMetadata> {
438→  const source: ExtractPhotoMetadataSource = options.source ?? "upload_buffer";
439→  const exifAttempt = await safeParseExif(imageBuffer, {
440→    gps: true,
441→    exif: true,
442→    tiff: true,
443→    pick: [
444→      "latitude",
445→      "longitude",
446→      "lat",
447→      "lon",
448→      "lng",
449→      "gps",
450→      "GPSLatitude",
451→      "GPSLongitude",
452→      "GPSLatitudeRef",
453→      "GPSLongitudeRef",
454→      "DateTimeOriginal",
455→      "DateTimeDigitized",
456→      "CreateDate",
457→      "ModifyDate",
458→      "Make",
459→      "Model",
460→    ],
461→  });
462→  const gpsAttempt = await safeParseGps(imageBuffer);
