468→  const gps = extractGps(merged);
469→  const capturedAt =
470→    parseDateIso(merged.DateTimeOriginal) ??
471→    parseDateIso(merged.DateTimeDigitized) ??
472→    parseDateIso(merged.CreateDate) ??
473→    parseDateIso(merged.ModifyDate);
