484→      gps,
485→      capturedAt,
486→      deviceMake,
487→      deviceModel,
488→      exifStatus,
489→      exifReason,
490→      exifSource: source,
491→    };
492→  }
493→
494→  const format = detectImageFormat(imageBuffer);
495→  const hasParseError = Boolean(exifAttempt.error || gpsAttempt.error);
496→  if (isUnsupportedExifFormat(format)) {
