527→export async function extractPhotoMetadataFromUrl(photoUrl: string): Promise<ExtractedPhotoMetadata | null> {
528→  if (!photoUrl || !isHttpUrl(photoUrl)) return null;
529→
530→  const source: ExtractPhotoMetadataSource = "remote_url";
531→  const controller = new AbortController();
532→  const timeout = setTimeout(() => controller.abort(), REMOTE_FETCH_TIMEOUT_MS);
533→  try {
534→    const response = await fetch(photoUrl, { signal: controller.signal });
535→    const mime = normalizeString(response.headers.get("content-type"));
536→    const ext = inferRemoteExt(photoUrl);
537→    if (!response.ok) {
538→      return createExtractedPhotoMetadata(
539→        "parse_error",
540→        withContext(`Unable to fetch remote photo for EXIF recovery (HTTP ${response.status})`, { source, mime, ext }),
541→        source,
542→      );
543→    }
544→    const arrayBuffer = await response.arrayBuffer();
545→    const byteLength = arrayBuffer.byteLength;
546→    if (!byteLength) {
547→      return createExtractedPhotoMetadata(
548→        "missing",
549→        withContext("Remote photo is empty; EXIF recovery skipped", { source, mime, ext, byteLength }),
550→        source,
551→      );
552→    }
553→    if (byteLength > MAX_REMOTE_METADATA_BYTES) {
554→      return createExtractedPhotoMetadata(
555→        "parse_error",
556→        withContext(`Remote photo exceeds EXIF fetch limit (${MAX_REMOTE_METADATA_BYTES} bytes)`, {
557→          source,
558→          mime,
559→          ext,
560→          byteLength,
561→        }),
562→        source,
563→      );
564→    }
565→    return await extractPhotoMetadata(Buffer.from(arrayBuffer), { source, mime, ext, byteLength });
566→  } catch (error) {
567→    const timeoutMessage = error instanceof Error && error.name === "AbortError";
568→    const reason = timeoutMessage
569→      ? `Timed out fetching remote photo after ${REMOTE_FETCH_TIMEOUT_MS}ms`
570→      : "Unable to fetch remote photo for EXIF recovery";
571→    return createExtractedPhotoMetadata("parse_error", withContext(reason, { source, ext: inferRemoteExt(photoUrl) }), source);
572→  } finally {
573→    clearTimeout(timeout);
574→  }
575→}
