337→  const dLon = toRad(b.longitude - a.longitude);
338→  const lat1 = toRad(a.latitude);
339→  const lat2 = toRad(b.latitude);
340→  const sinLat = Math.sin(dLat / 2);
341→  const sinLon = Math.sin(dLon / 2);
342→  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLon * sinLon;
343→  return 2 * 6371 * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h));
344→}
345→
346→function roundKm(input) {
347→  return Number(input.toFixed(3));
348→}
349→
350→function buildPhotoFraudMetadata({ extracted, submissionLocation, ipLocation, submissionMatchThresholdKm, ipMatchThresholdKm }) {
351→  if (!extracted) return null;
352→  const gps = extracted.gps;
353→  const submissionDistanceRaw = gps && submissionLocation ? haversineKm(submissionLocation, gps) : null;
354→  const ipDistanceRaw = gps && ipLocation ? haversineKm(ipLocation, gps) : null;
355→  const submissionDistanceKm = submissionDistanceRaw === null ? null : roundKm(submissionDistanceRaw);
356→  const ipDistanceKm = ipDistanceRaw === null ? null : roundKm(ipDistanceRaw);
357→  return {
358→    gps,
359→    capturedAt: extracted.capturedAt,
360→    deviceMake: extracted.deviceMake,
361→    deviceModel: extracted.deviceModel,
362→    submissionDistanceKm,
363→    submissionGpsMatch: submissionDistanceKm === null ? null : submissionDistanceKm <= submissionMatchThresholdKm,
364→    ipDistanceKm,
365→    ipGpsMatch: ipDistanceKm === null ? null : ipDistanceKm <= ipMatchThresholdKm,
366→    exifStatus: extracted.exifStatus,
367→    exifReason: extracted.exifReason,
368→    exifSource: extracted.exifSource,
369→  };
370→}
371→
372→function mergePhotoMetadata(existing, recovered, hasUrl) {
373→  if (!hasUrl) return existing ?? null;
374→  if (existing && !isPhotoMetadataEffectivelyEmpty(existing)) return existing;
375→  if (recovered) return recovered;
376→  return existing ?? null;
377→}
378→
379→function buildFraudCheck({ location, existingFraudCheck, primaryPhoto, secondaryPhoto }) {
380→  return {
381→    submissionLocation: existingFraudCheck?.submissionLocation ?? location,
382→    effectiveLocation: existingFraudCheck?.effectiveLocation ?? location,
383→    ipLocation: existingFraudCheck?.ipLocation ?? null,
384→    primaryPhoto,
385→    secondaryPhoto,
386→    submissionMatchThresholdKm: existingFraudCheck?.submissionMatchThresholdKm ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM,
387→    ipMatchThresholdKm: existingFraudCheck?.ipMatchThresholdKm ?? DEFAULT_IP_MATCH_THRESHOLD_KM,
388→  };
389→}
