391→async function main() {
392→  loadEnv();
393→  const args = parseArgs(process.argv.slice(2));
394→  const postgresUrl = resolvePostgresUrl();
395→  if (!postgresUrl) {
396→    throw new Error("POSTGRES_URL (or POSTGRES_PRISMA_URL / POSTGRES_URL_NON_POOLING) is required");
397→  }
398→  if (args.write) {
399→    const driver = (process.env.DATA_STORE_DRIVER ?? "").trim().toLowerCase();
400→    if (driver !== "postgres") {
401→      throw new Error("Write mode is only allowed when DATA_STORE_DRIVER=postgres");
402→    }
403→  }
404→
405→  const pool = new Pool({
406→    connectionString: postgresUrl,
407→    ssl: process.env.POSTGRES_SSL_NO_VERIFY === "true" ? { rejectUnauthorized: false } : undefined,
408→  });
409→
410→  const stats = {
411→    scanned: 0,
412→    recoverable: 0,
413→    recovered: 0,
414→    unchanged: 0,
415→    parseFailures: 0,
416→    unsupportedFormat: 0,
417→  };
418→  const recoveredIds = [];
419→
420→  try {
421→    const result = await pool.query(
422→      `
423→        select id, latitude, longitude, details, photo_url
424→        from point_events
425→        order by created_at asc
426→      `,
427→    );
428→
429→    for (const row of result.rows) {
430→      stats.scanned += 1;
431→      const details = row.details && typeof row.details === "object" ? row.details : {};
432→      const location = {
433→        latitude: typeof row.latitude === "number" ? row.latitude : Number(row.latitude),
434→        longitude: typeof row.longitude === "number" ? row.longitude : Number(row.longitude),
435→      };
436→      if (!Number.isFinite(location.latitude) || !Number.isFinite(location.longitude)) {
437→        stats.unchanged += 1;
438→        continue;
439→      }
440→
441→      const primaryUrl = typeof row.photo_url === "string" ? row.photo_url.trim() : "";
442→      const secondaryUrl = typeof details.secondPhotoUrl === "string" ? details.secondPhotoUrl.trim() : "";
443→      const existingFraudCheck = parseFraudCheck(details.fraudCheck, location);
444→
445→      const needsPrimary = Boolean(primaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.primaryPhoto);
446→      const needsSecondary = Boolean(secondaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.secondaryPhoto);
447→      if (!needsPrimary && !needsSecondary) {
448→        stats.unchanged += 1;
449→        continue;
450→      }
451→
452→      stats.recoverable += 1;
453→
454→      const primaryExtracted = needsPrimary ? await extractPhotoMetadataFromUrl(primaryUrl) : null;
455→      const secondaryExtracted = needsSecondary ? await extractPhotoMetadataFromUrl(secondaryUrl) : null;
456→
457→      if (primaryExtracted?.exifStatus === "parse_error") stats.parseFailures += 1;
458→      if (secondaryExtracted?.exifStatus === "parse_error") stats.parseFailures += 1;
459→      if (primaryExtracted?.exifStatus === "unsupported_format") stats.unsupportedFormat += 1;
460→      if (secondaryExtracted?.exifStatus === "unsupported_format") stats.unsupportedFormat += 1;
461→
462→      const recoveredPrimary = buildPhotoFraudMetadata({
463→        extracted: primaryExtracted,
464→        submissionLocation: location,
465→        ipLocation: existingFraudCheck?.ipLocation ?? null,
466→        submissionMatchThresholdKm: existingFraudCheck?.submissionMatchThresholdKm ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM,
467→        ipMatchThresholdKm: existingFraudCheck?.ipMatchThresholdKm ?? DEFAULT_IP_MATCH_THRESHOLD_KM,
468→      });
469→      const recoveredSecondary = buildPhotoFraudMetadata({
470→        extracted: secondaryExtracted,
471→        submissionLocation: location,
472→        ipLocation: existingFraudCheck?.ipLocation ?? null,
473→        submissionMatchThresholdKm: existingFraudCheck?.submissionMatchThresholdKm ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM,
474→        ipMatchThresholdKm: existingFraudCheck?.ipMatchThresholdKm ?? DEFAULT_IP_MATCH_THRESHOLD_KM,
475→      });
476→
477→      const primaryPhoto = mergePhotoMetadata(existingFraudCheck?.primaryPhoto ?? null, recoveredPrimary, Boolean(primaryUrl));
478→      const secondaryPhoto = mergePhotoMetadata(existingFraudCheck?.secondaryPhoto ?? null, recoveredSecondary, Boolean(secondaryUrl));
479→      const nextFraudCheck = buildFraudCheck({
480→        location,
481→        existingFraudCheck,
482→        primaryPhoto,
483→        secondaryPhoto,
484→      });
485→
486→      const existingSerialized = JSON.stringify(details.fraudCheck ?? null);
487→      const nextSerialized = JSON.stringify(nextFraudCheck);
488→      if (existingSerialized === nextSerialized) {
489→        stats.unchanged += 1;
490→        continue;
491→      }
492→
493→      stats.recovered += 1;
494→      if (recoveredIds.length < 20) recoveredIds.push(row.id);
495→
496→      if (args.write) {
497→        const nextDetails = { ...details, fraudCheck: nextFraudCheck };
498→        await pool.query(
499→          `
500→            update point_events
501→            set details = $2::jsonb
502→            where id = $1::uuid
503→          `,
504→          [row.id, JSON.stringify(nextDetails)],
505→        );
506→      }
507→    }
508→  } finally {
509→    await pool.end();
510→  }
511→
512→  console.info("EXIF Backfill Summary");
513→  console.info(`mode: ${args.write ? "write" : "dry-run"}`);
514→  console.info(`scanned: ${stats.scanned}`);
515→  console.info(`recoverable: ${stats.recoverable}`);
516→  console.info(`recovered: ${stats.recovered}`);
517→  console.info(`unchanged: ${stats.unchanged}`);
518→  console.info(`parse_failures: ${stats.parseFailures}`);
519→  console.info(`unsupported_format: ${stats.unsupportedFormat}`);
520→  if (recoveredIds.length > 0) {
521→    console.info(`sample_recovered_ids: ${recoveredIds.join(", ")}`);
522→  }
523→}
524→
525→main().catch((error) => {
526→  console.error(error instanceof Error ? error.message : String(error));
527→  process.exitCode = 1;
528→});
