 38→function dataUrlToBytes(dataUrl: string): Uint8Array | null {
 39→  const commaIndex = dataUrl.indexOf(',');
 40→  if (commaIndex === -1) return null;
 41→  const base64 = dataUrl.slice(commaIndex + 1);
 42→  if (!base64) return null;
 43→  const binary = atob(base64);
 44→  const bytes = new Uint8Array(binary.length);
 45→  for (let i = 0; i < binary.length; i += 1) {
 46→    bytes[i] = binary.charCodeAt(i);
 47→  }
 48→  return bytes;
 49→}
 50→
 51→function bytesToDataUrl(bytes: Uint8Array, mime: string): string {
 52→  let binary = '';
 53→  for (let i = 0; i < bytes.length; i += 1) {
 54→    binary += String.fromCharCode(bytes[i] ?? 0);
 55→  }
 56→  return `data:${mime};base64,${btoa(binary)}`;
 57→}
 58→
 59→function extractJpegExifSegment(bytes: Uint8Array): Uint8Array | null {
 60→  if (bytes.length < 4) return null;
 61→  if (bytes[0] !== 0xff || bytes[1] !== 0xd8) return null;
 62→
 63→  let offset = 2;
 64→  while (offset + 4 <= bytes.length) {
 65→    if (bytes[offset] !== 0xff) {
 66→      offset += 1;
 67→      continue;
 68→    }
 69→
 70→    const marker = bytes[offset + 1];
 71→    if (marker === 0xd8 || marker === 0x01 || (marker >= 0xd0 && marker <= 0xd7)) {
 72→      offset += 2;
 73→      continue;
 74→    }
 75→    if (marker === 0xda || marker === 0xd9) break;
 76→
 77→    const segmentLength = ((bytes[offset + 2] ?? 0) << 8) | (bytes[offset + 3] ?? 0);
 78→    if (segmentLength < 2) break;
 79→    const segmentEnd = offset + 2 + segmentLength;
 80→    if (segmentEnd > bytes.length) break;
 81→
 82→    if (marker === 0xe1 && segmentLength >= 8) {
 83→      const signature = String.fromCharCode(
 84→        bytes[offset + 4] ?? 0,
 85→        bytes[offset + 5] ?? 0,
 86→        bytes[offset + 6] ?? 0,
 87→        bytes[offset + 7] ?? 0,
 88→        bytes[offset + 8] ?? 0,
 89→        bytes[offset + 9] ?? 0,
 90→      );
 91→      if (signature === 'Exif\0\0') {
 92→        return bytes.slice(offset, segmentEnd);
 93→      }
 94→    }
 95→
 96→    offset = segmentEnd;
 97→  }
 98→
 99→  return null;
100→}
101→
102→function injectExifIntoJpeg(compressedBytes: Uint8Array, exifSegment: Uint8Array): Uint8Array | null {
103→  if (compressedBytes.length < 2) return null;
104→  if (compressedBytes[0] !== 0xff || compressedBytes[1] !== 0xd8) return null;
105→  if (!exifSegment.length) return null;
106→
107→  const merged = new Uint8Array(compressedBytes.length + exifSegment.length);
108→  merged[0] = compressedBytes[0];
109→  merged[1] = compressedBytes[1];
110→  merged.set(exifSegment, 2);
111→  merged.set(compressedBytes.slice(2), 2 + exifSegment.length);
112→  return merged;
113→}
114→
115→async function preserveJpegExif(originalFile: File, compressedDataUrl: string): Promise<string> {
116→  if (!JPEG_MIME_TYPES.has((originalFile.type || '').toLowerCase())) return compressedDataUrl;
117→
118→  const originalBytes = new Uint8Array(await originalFile.arrayBuffer());
119→  const exifSegment = extractJpegExifSegment(originalBytes);
120→  if (!exifSegment) return compressedDataUrl;
121→
122→  const compressedBytes = dataUrlToBytes(compressedDataUrl);
123→  if (!compressedBytes) return compressedDataUrl;
124→  if (extractJpegExifSegment(compressedBytes)) return compressedDataUrl;
125→
126→  const merged = injectExifIntoJpeg(compressedBytes, exifSegment);
127→  if (!merged) return compressedDataUrl;
128→  return bytesToDataUrl(merged, 'image/jpeg');
129→}
