296→  const fileToBase64 = async (file: File) => {
297→    const readAsDataUrl = (target: Blob) =>
298→      new Promise<string>((resolve, reject) => {
299→        const reader = new FileReader();
300→        reader.onload = () => {
301→          if (typeof reader.result === 'string') {
302→            resolve(reader.result);
303→            return;
304→          }
305→          reject(new Error('Unable to read file.'));
306→        };
307→        reader.onerror = () => reject(new Error('Unable to read file.'));
308→        reader.readAsDataURL(target);
309→      });
310→
311→    if (!file.type.startsWith('image/')) {
312→      return await readAsDataUrl(file);
313→    }
314→
315→    // Keep original capture when possible so EXIF (GPS/time/device) reaches server-side forensics.
316→    if (file.size <= MAX_SUBMISSION_IMAGE_BYTES) {
317→      return await readAsDataUrl(file);
318→    }
319→
320→    const loadImage = (objectUrl: string) =>
321→      new Promise<HTMLImageElement>((resolve, reject) => {
322→        const img = new Image();
323→        img.onload = () => resolve(img);
324→        img.onerror = () => reject(new Error('Unable to decode image.'));
325→        img.src = objectUrl;
326→      });
327→
328→    const objectUrl = URL.createObjectURL(file);
329→    try {
330→      const img = await loadImage(objectUrl);
331→      const maxDimension = Math.max(img.width, img.height);
332→      const scale = maxDimension > MAX_UPLOAD_DIMENSION ? MAX_UPLOAD_DIMENSION / maxDimension : 1;
333→      const width = Math.max(1, Math.round(img.width * scale));
334→      const height = Math.max(1, Math.round(img.height * scale));
335→      const canvas = document.createElement('canvas');
336→      canvas.width = width;
337→      canvas.height = height;
338→      const ctx = canvas.getContext('2d');
339→      if (!ctx) {
340→        return await readAsDataUrl(file);
341→      }
342→      ctx.drawImage(img, 0, 0, width, height);
343→      const quality = isLowEndDevice ? IMAGE_QUALITY_LOW_END : IMAGE_QUALITY_DEFAULT;
344→      const compressed = canvas.toDataURL('image/jpeg', quality);
345→      return await preserveJpegExif(file, compressed);
346→    } catch {
347→      return await readAsDataUrl(file);
348→    } finally {
349→      URL.revokeObjectURL(objectUrl);
350→    }
351→  };
