 13→async function extractResponseMessage(response: Response): Promise<string> {
 14→  const fallback = response.statusText || DEFAULT_SYNC_ERROR;
 15→  const contentType = response.headers.get('content-type')?.toLowerCase() ?? '';
 16→
 17→  if (contentType.includes('application/json')) {
 18→    try {
